const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const basePremiumFor = (itemType: string): number => BASE_PREMIUMS[itemType] ?? 0;

const sumBasePremiums = (items: { type: string }[]): number =>
  items.reduce((total, item) => total + basePremiumFor(item.type), 0);

export const runScenario = (scenario: any): unknown => {
  const items = scenario?.steps?.[0]?.items ?? [];
  const basePremium = sumBasePremiums(items);
  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const premium = basePremium + surcharge + PROCESSING_FEE;
  return { results: [{ premium }] };
};

